import { EventSearchResult, RawEventData } from '../types';

const API_URL = 'https://api.ftcscout.org/graphql';

async function gql(query: string, variables: Record<string, unknown> = {}): Promise<any> {
  const res = await fetch(API_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ query, variables }),
  });
  if (!res.ok) throw new Error(`API error ${res.status}: ${res.statusText}`);
  const json = await res.json();
  if (json.errors?.length) throw new Error(json.errors.map((e: any) => e.message).join('; '));
  return json.data;
}

export const SEASONS = [
  { label: '2025-2026', value: 2025 },
  { label: '2024-2025', value: 2024 },
  { label: '2023-2024', value: 2023 },
  { label: '2022-2023', value: 2022 },
  { label: '2021-2022', value: 2021 },
];

export async function searchEvents(query: string, season: number): Promise<EventSearchResult[]> {
  if (!query || query.trim().length < 2) return [];
  const data = await gql(
    `query SearchEvents($season: Int!, $query: String!) {
      eventsSearch(season: $season, query: $query) {
        code name start end type
        location { venue city state country }
      }
    }`,
    { season, query: query.trim() }
  );
  return (data.eventsSearch || []).map((e: any) => ({ ...e, season }));
}

export async function getEventDetails(code: string, season: number): Promise<RawEventData> {
  const data = await gql(
    `query GetEvent($season: Int!, $code: String!) {
      eventByCode(season: $season, code: $code) {
        code name start end finished
        location { venue city state country }
        teams { teamNumber }
        matches {
          matchNum hasBeenPlayed
          teams { teamNumber alliance surrogate noShow dq }
          scores {
            red { totalPoints }
            blue { totalPoints }
          }
        }
      }
    }`,
    { season, code }
  );
  const event = data.eventByCode;
  if (!event) throw new Error(`Event "${code}" not found for season ${season}`);
  return event;
}

export function extractScore(score: any): number {
  if (!score) return 0;
  return score.totalPoints ?? score.total ?? score.totalPointsNp ?? 0;
}

export function getTeamAlliance(alliance: string): 'red' | 'blue' | null {
  const a = alliance.toLowerCase();
  if (a.includes('red') || a === 'r1' || a === 'r2' || a === 'r') return 'red';
  if (a.includes('blue') || a === 'b1' || a === 'b2' || a === 'b') return 'blue';
  return null;
}

/**
 * Fetch the highest OPR a team achieved at any event that started
 * strictly BEFORE eventStartDate in the given season.
 * This ensures we never use data from future events when simulating.
 */
async function fetchTeamPeakOPRBeforeDate(
  teamNumber: number,
  season: number,
  eventStartDate: string
): Promise<number> {
  const data = await gql(
    `query GetTeamSeasonDates($number: Int!, $season: Int!) {
      teamByNumber(number: $number) {
        events(season: $season) {
          event { start }
          opr { total }
        }
      }
    }`,
    { number: teamNumber, season }
  );

  const events: any[] = data?.teamByNumber?.events ?? [];
  const cutoff = new Date(eventStartDate).getTime();

  const validOPRs = events
    .filter((e: any) => {
      const t = new Date(e?.event?.start ?? '').getTime();
      return !isNaN(t) && t < cutoff;
    })
    .map((e: any) => e?.opr?.total ?? 0)
    .filter((o: number) => typeof o === 'number' && o > 0);

  return validOPRs.length > 0 ? Math.max.apply(null, validOPRs) : 0;
}

/**
 * Load peak pre-event OPRs for all teams in parallel.
 * No fallback to event-level OPR — if a team has no prior events,
 * their OPR is 0.
 */
export async function loadTeamBestOPRs(
  teamNumbers: number[],
  season: number,
  eventStartDate: string
): Promise<Map<number, number>> {
  const settled = await Promise.allSettled(
    teamNumbers.map(num => fetchTeamPeakOPRBeforeDate(num, season, eventStartDate))
  );

  const result = new Map<number, number>();
  teamNumbers.forEach((num, i) => {
    const r = settled[i];
    result.set(num, r.status === 'fulfilled' ? r.value : 0);
  });
  return result;
}

// Legacy export
export const fetchEventData = async (eventName: string) => ({
  name: eventName, location: 'Location TBD', date: 'Date TBD', matches: [],
});
export const fetchEventsByName = searchEvents;
